import{_ as d,o,c as a,a2 as s}from"./chunks/framework.BZO4qERu.js";const h=JSON.parse('{"title":"Claude SDK 真实飞书验证计划","description":"","frontmatter":{},"headers":[],"relativePath":"testing/claude-sdk-real-feishu.md","filePath":"testing/claude-sdk-real-feishu.md","lastUpdated":1780470661000}'),i={name:"testing/claude-sdk-real-feishu.md"};function l(c,e,t,r,n,u){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="claude-sdk-真实飞书验证计划" tabindex="-1">Claude SDK 真实飞书验证计划 <a class="header-anchor" href="#claude-sdk-真实飞书验证计划" aria-label="Permalink to &quot;Claude SDK 真实飞书验证计划&quot;">​</a></h1><p>本文只记录 Claude SDK/无头 Claude provider 的专项背景和验收要求。真实飞书 E2E 的通用运行方式、场景组织、gate 和排障流程见 <a href="./real-feishu/">真实飞书 E2E</a>。</p><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>2026-06-02 的 Claude runtime 排障暴露了一个核心问题：Claude Code 已经写出 JSONL 响应，但 <code>BridgeSession.runtime.claude.sessionId</code> 保存的是 bridge 自己的 session id，而不是真实 Claude Code session id。结果 mirror reconciler 认为 Claude thread 不存在，用户在 IM 里看到的是“Claude 不回复”。</p><p>典型日志形态：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clearing dangling Claude thread f63c88b5-0cca-4c5d-ad91-58d1e69f02c9:</span></span>
<span class="line"><span>Claude thread no longer exists locally</span></span></code></pre></div><p>真实故障不是模型没有输出，而是 bridge 没有把 IM session 绑定到真实 Claude JSONL session。</p><h2 id="现有-pty-路径的脆弱点" tabindex="-1">现有 pty 路径的脆弱点 <a class="header-anchor" href="#现有-pty-路径的脆弱点" aria-label="Permalink to &quot;现有 pty 路径的脆弱点&quot;">​</a></h2><p>当前 pty provider 在注入 prompt 后再猜测 Claude 身份：</p><ol><li>启动或复用 Claude Code TUI pty。</li><li>把 prompt 写入 TUI。</li><li>等待 <code>CTI_CLAUDE_PTY_JSONL_DISCOVERY_TIMEOUT_MS</code>，默认 <code>2500ms</code>。</li><li>扫描 <code>~/.claude/projects/&lt;cwd&gt;/*.jsonl</code>，查找注入 prompt 后更新的文件。</li><li>找到后发送 <code>status { session_id, cwd, transcript_path }</code>。</li><li>interactive runner 写入 <code>runtime.claude.sessionId</code>，再触发 mirror reconcile。</li></ol><p>如果短窗口内没有扫到文件，<code>status</code> 事件不会发出，runner 不会激活 Claude mirror 输出，session 可能长期绑定到无效占位 id。</p><h2 id="sdk-与无头-cli-能力" tabindex="-1">SDK 与无头 CLI 能力 <a class="header-anchor" href="#sdk-与无头-cli-能力" aria-label="Permalink to &quot;SDK 与无头 CLI 能力&quot;">​</a></h2><p>Claude CLI / <code>ccr code</code> 暴露了这些与会话身份相关的能力：</p><ul><li><code>--session-id &lt;uuid&gt;</code>：使用指定 session id。</li><li><code>--resume [value]</code>：按 session id 恢复对话。</li><li><code>--continue</code>：继续当前目录最近一次对话。</li><li><code>--fork-session</code>：恢复时 fork 出新 session。</li><li><code>-p, --print</code>：非交互输出模式。</li><li><code>--output-format stream-json</code>：输出结构化流。</li><li><code>--input-format stream-json</code>：接收结构化流输入。</li></ul><p>Claude Agent SDK 也提供更适合 bridge 的事件路径：</p><ul><li>TypeScript 包为 <code>@anthropic-ai/claude-agent-sdk</code>。</li><li><code>query()</code> 支持 <code>string | AsyncIterable&lt;SDKUserMessage&gt;</code>。</li><li>streaming input 支持排队消息、中断、权限请求、图片和持久 session。</li><li>可用 slash command 会在 <code>system/init</code> 消息的 <code>slash_commands</code> 中暴露。</li><li>SDK 暴露 <code>listSessions()</code>、<code>getSessionMessages()</code> 等 session 工具。</li></ul><p>参考：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://code.claude.com/docs/en/agent-sdk/typescript</span></span>
<span class="line"><span>https://code.claude.com/docs/en/agent-sdk/streaming-vs-single-mode</span></span>
<span class="line"><span>https://code.claude.com/docs/en/agent-sdk/slash-commands</span></span>
<span class="line"><span>https://code.claude.com/docs/en/agent-sdk/sessions</span></span>
<span class="line"><span>https://code.claude.com/docs/en/headless</span></span></code></pre></div><h2 id="provider-设计方向" tabindex="-1">Provider 设计方向 <a class="header-anchor" href="#provider-设计方向" aria-label="Permalink to &quot;Provider 设计方向&quot;">​</a></h2><p>bridge 不应把 Claude 身份当成事后猜测结果。Claude runtime 身份应在 turn 初始化前后明确获得。</p><p>目标行为：</p><ul><li>新增 Claude SDK 或 headless provider。</li><li>IM Claude runtime turn 可按 provider 配置选择 <code>pty</code> 或 <code>sdk</code>。</li><li>pty 保留为 attach/debug/CCR 场景；SDK provider 作为原生事件路径。</li><li>首次 turn 没有 Claude session id 时，生成 UUID，或立即读取 SDK init/result 中的 session id。</li><li>把真实 id 写入 <code>runtime.claude.sessionId</code>。</li><li>新 session 使用 <code>--session-id &lt;uuid&gt;</code> 或 SDK session 选项；已有 session 使用 <code>resume</code> / <code>--resume &lt;session-id&gt;</code>。</li><li>把 SDK 消息转换为 bridge 现有 SSE event vocabulary。</li><li>SDK 报告 session id 后立刻发送 <code>status</code>，身份明确后触发 mirror reconcile。</li><li>从 SDK stream 中发出 text/tool/task/context/result 事件。</li></ul><p>当前实现状态：</p><ul><li><code>runtime.claude.provider</code>、<code>CTI_CLAUDE_PROVIDER</code>、<code>bridge_claude_provider</code> 和会话级 <code>runtime.claude.provider</code> 支持 <code>pty|sdk</code>。</li><li><code>/provider</code> 和 <code>/p</code> 在 Claude runtime 下切换 <code>pty|sdk</code>；Codex runtime 下仍切换 <code>sdk|pty|tmux</code>。</li><li><code>sdk</code> provider 基于 <code>@anthropic-ai/claude-agent-sdk query()</code>，把 init/result/assistant 文本转成 bridge 现有 SSE vocabulary。</li><li>默认仍是 <code>pty</code>，避免改变当前 CCR-backed Claude Code 的真实飞书路径。</li></ul><p>Slash command 边界：</p><ul><li><code>/t</code>、<code>/his</code>、<code>/runtime</code>、<code>/new</code>、<code>/auto</code>、<code>/file</code>、<code>/shell</code> 等仍由 Codex-to-IM 处理。</li><li>只有 bridge command dispatch 拒绝后，Claude slash command 才传给 Claude。</li><li>provider 应把 SDK <code>slash_commands</code> 列表暴露给诊断。</li><li>SDK 模式不支持的命令应给出可见诊断，不能静默退回 pty 行为。</li></ul><h2 id="真实飞书验收要求" tabindex="-1">真实飞书验收要求 <a class="header-anchor" href="#真实飞书验收要求" aria-label="Permalink to &quot;真实飞书验收要求&quot;">​</a></h2><p>Claude SDK 真实飞书场景必须满足通用 <a href="./real-feishu/">真实飞书 E2E</a> gate，并额外证明：</p><ul><li><code>claude-sdk</code> 使用 SDK 原生事件和 <code>im:</code> direct stream key，不要求 <code>claude_jsonl_found</code>。</li><li><code>claude-pty</code> 才要求 Claude JSONL/mirror 证据，JSONL 查找必须兼容 Claude Code 对 cwd 的编码规则。</li><li>SDK final prompt 的 bot 回复本身必须包含本轮唯一 marker，不能把用户原始消息里的 marker 当成通过证据。</li><li>CCR-backed <code>claude-sdk</code> 测试必须通过 <code>ccr activate/status/start</code> 准备 SDK subprocess env。</li><li>使用 <code>--fake-ccr</code> 时，必须同时证明 fake backend 收到请求，并且最终 bot <code>reply_to</code> 包含 fake marker。</li><li>fake 代理只提供可控模型输出，不能替代 provider 输出路径、<code>reply_to</code> 和清理 gate。</li></ul><h2 id="未决问题" tabindex="-1">未决问题 <a class="header-anchor" href="#未决问题" aria-label="Permalink to &quot;未决问题&quot;">​</a></h2><ul><li><code>pathToClaudeCodeExecutable</code> 是否可以直接指向 <code>ccr</code>。</li><li>SDK 能否加载 CCR 的同一套配置，而不是 shell 到 <code>ccr code</code>。</li><li>对 CCR 兼容而言，headless CLI 是否比 TypeScript SDK 更稳。</li><li>SDK 权限请求如何映射到现有飞书权限卡片。</li></ul>`,31)])])}const m=d(i,[["render",l]]);export{h as __pageData,m as default};
